import{_ as p,c as k,f as r,w as i,S as h,a,b as s,d as t,e as n,r as d,o as l}from"./chunks/nolebase.BaxMql6k.js";const Q=JSON.parse('{"title":"重設 MySQL Root 密碼（Windows） | LucasHsu.dev","description":"忘記 MySQL root 密碼怎麼辦？本文教你在 Windows 上使用 --skip-grant-tables 模式重設 root 密碼，包含完整步驟與常見問題解答。","frontmatter":{"title":"重設 MySQL Root 密碼（Windows） | LucasHsu.dev","description":"忘記 MySQL root 密碼怎麼辦？本文教你在 Windows 上使用 --skip-grant-tables 模式重設 root 密碼，包含完整步驟與常見問題解答。","head":[["meta",{"name":"keywords","content":"MySQL, root密碼重設, Windows, skip-grant-tables, 資料庫管理"}],["meta",{"property":"og:title","content":"重設 MySQL Root 密碼（Windows）"}],["meta",{"property":"og:description","content":"忘記 MySQL root 密碼怎麼辦？本文教你在 Windows 上使用 --skip-grant-tables 模式重設 root 密碼，包含完整步驟與常見問題解答。"}],["meta",{"property":"og:type","content":"article"}]]},"headers":[],"relativePath":"database/mysql-reset-root-password-windows.md","filePath":"database/mysql-reset-root-password-windows.md","lastUpdated":1782551622000}'),E={name:"database/mysql-reset-root-password-windows.md"},c=n(`<h1 id="重設-mysql-root-密碼-windows" tabindex="-1">重設 MySQL Root 密碼（Windows） <a class="header-anchor" href="#重設-mysql-root-密碼-windows" aria-label="Permalink to &quot;重設 MySQL Root 密碼（Windows）&quot;">​</a></h1><blockquote><p>📝 TL;DR 當你忘記 MySQL root 密碼時，可以在 Windows 上透過 <code>--skip-grant-tables</code> 跳過權限驗證，直接登入資料庫修改密碼。本文提供完整的 6 步驟操作指南，包含服務停止、免密登入、密碼修改、服務重啟與驗證。</p></blockquote><h2 id="前置知識" tabindex="-1">前置知識 <a class="header-anchor" href="#前置知識" aria-label="Permalink to &quot;前置知識&quot;">​</a></h2><p>在開始之前，建議你先了解以下概念：</p><ul><li><strong>MySQL 服務管理</strong> - 知道如何用 <code>net stop/start</code> 控制 MySQL 服務</li><li><strong>PowerShell 基礎操作</strong> - 需要以系統管理員身分執行指令</li><li><strong>MySQL 權限系統</strong> - 理解 grant tables 的作用與 <code>--skip-grant-tables</code> 的風險</li></ul><h2 id="什麼時候需要重設-root-密碼" tabindex="-1">什麼時候需要重設 Root 密碼？ <a class="header-anchor" href="#什麼時候需要重設-root-密碼" aria-label="Permalink to &quot;什麼時候需要重設 Root 密碼？&quot;">​</a></h2><h3 id="為什麼會需要這個操作" tabindex="-1">為什麼會需要這個操作？ <a class="header-anchor" href="#為什麼會需要這個操作" aria-label="Permalink to &quot;為什麼會需要這個操作？&quot;">​</a></h3><p>常見情境：</p><ul><li><strong>遺忘密碼</strong> - 最常見的原因，長時間未登入導致忘記 root 密碼</li><li><strong>接手舊系統</strong> - 取得專案但無人知道資料庫密碼</li><li><strong>安全性審計</strong> - 定期輪換密碼，但舊密碼未留存</li></ul><h3 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h3><p>MySQL 的權限資訊儲存在 <code>mysql</code> 系統資料庫的 grant tables（如 <code>user</code>、<code>db</code>、<code>tables_priv</code> 等）中。啟動 MySQL 時加上 <code>--skip-grant-tables</code> 參數，會<strong>跳過這些權限表的載入與驗證</strong>，讓任何使用者無需密碼即可連線並擁有所有權限。</p><div class="warning custom-block"><p class="custom-block-title">⚠️ 安全性警告</p><p><code>--skip-grant-tables</code> 會<strong>完全關閉權限驗證</strong>，任何人都能無密碼登入並擁有最高權限。請務必：</p><ol><li>僅在本機、受信任環境操作</li><li>操作完成後<strong>立即重新啟動正常模式</strong></li><li>考慮加上 <code>--skip-networking</code> 禁止遠端連線（Windows 上用 <code>--shared-memory</code> 達成類似效果）</li></ol></div><h2 id="💻-完整操作步驟" tabindex="-1">💻 完整操作步驟 <a class="header-anchor" href="#💻-完整操作步驟" aria-label="Permalink to &quot;💻 完整操作步驟&quot;">​</a></h2><h3 id="步驟-1-停止-mysql-服務" tabindex="-1">步驟 1：停止 MySQL 服務 <a class="header-anchor" href="#步驟-1-停止-mysql-服務" aria-label="Permalink to &quot;步驟 1：停止 MySQL 服務&quot;">​</a></h3><p>以<strong>系統管理員</strong>開啟 PowerShell：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">net stop MySQL80</span></span></code></pre></div><blockquote><p><strong>注意</strong>：服務名稱可能因安裝版本不同而有所差異（如 <code>MySQL</code>、<code>MySQL57</code>、<code>MySQL80</code>、<code>MySQL84</code>）。可用 <code>services.msc</code> 或 <code>sc query state= all | findstr MySQL</code> 確認正確服務名稱。</p></blockquote><hr><h3 id="步驟-2-用-skip-grant-tables-啟動-mysql" tabindex="-1">步驟 2：用 <code>--skip-grant-tables</code> 啟動 MySQL <a class="header-anchor" href="#步驟-2-用-skip-grant-tables-啟動-mysql" aria-label="Permalink to &quot;步驟 2：用 \`--skip-grant-tables\` 啟動 MySQL&quot;">​</a></h3><p>在同一個 PowerShell 視窗執行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">&amp;</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">C:\\Program Files\\MySQL\\MySQL Server 8.0\\bin\\mysqld.exe</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> --</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">defaults</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">file</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">=</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">C:\\ProgramData\\MySQL\\MySQL Server 8.0\\my.ini</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> --</span><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">skip-grant</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">tables </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">--</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">shared</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">memory</span></span></code></pre></div><p><strong>參數說明：</strong></p><table><thead><tr><th>參數</th><th>作用</th></tr></thead><tbody><tr><td><code>--defaults-file</code></td><td>指定設定檔路徑（確保讀取正確的 port、datadir 等設定）</td></tr><tr><td><code>--skip-grant-tables</code></td><td><strong>核心參數</strong>：跳過權限表驗證，允許無密碼登入</td></tr><tr><td><code>--shared-memory</code></td><td>Windows 專用：啟用共享記憶體協定，避免 TCP/IP 連線問題</td></tr></tbody></table><blockquote><p><strong>路徑可能不同</strong>：若你的 MySQL 安裝在其他位置，請調整 <code>mysqld.exe</code> 與 <code>my.ini</code> 的實際路徑。可用 <code>where mysqld</code> 尋找執行檔位置。</p></blockquote><blockquote><p>此指令會<strong>佔用該 PowerShell 視窗</strong>，MySQL 在前景執行。請<strong>另開新視窗</strong>進行下一步。</p></blockquote><hr><h3 id="步驟-3-另開-powershell-免密登入" tabindex="-1">步驟 3：另開 PowerShell，免密登入 <a class="header-anchor" href="#步驟-3-另開-powershell-免密登入" aria-label="Permalink to &quot;步驟 3：另開 PowerShell，免密登入&quot;">​</a></h3><p>開啟<strong>新的</strong> PowerShell 視窗（不需系統管理員權限），執行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">&amp;</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">C:\\Program Files\\MySQL\\MySQL Server 8.0\\bin\\mysql.exe</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> -</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">u root</span></span></code></pre></div><p>成功時會直接進入 MySQL 互動模式（<code>mysql&gt;</code> 提示字元），無需輸入密碼。</p><hr><h3 id="步驟-4-修改-root-密碼" tabindex="-1">步驟 4：修改 Root 密碼 <a class="header-anchor" href="#步驟-4-修改-root-密碼" aria-label="Permalink to &quot;步驟 4：修改 Root 密碼&quot;">​</a></h3><p>在 MySQL 互動模式中依序執行：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">FLUSH PRIVILEGES;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">ALTER</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> USER</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">root</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">@</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">localhost</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> IDENTIFIED </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">BY</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">你的新密碼</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">FLUSH PRIVILEGES;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">EXIT;</span></span></code></pre></div><p><strong>關鍵點解析：</strong></p><table><thead><tr><th>SQL 指令</th><th>用途</th></tr></thead><tbody><tr><td><code>FLUSH PRIVILEGES;</code></td><td><strong>必須先執行</strong>：在 skip-grant-tables 模式下，權限表未載入記憶體，需手動重載才能讓 <code>ALTER USER</code> 生效</td></tr><tr><td><code>ALTER USER ... IDENTIFIED BY</code></td><td>MySQL 8.0 修改密碼的標準語法</td></tr><tr><td><code>FLUSH PRIVILEGES;</code></td><td>再次重載，確保新密碼立即生效</td></tr><tr><td><code>EXIT;</code></td><td>離開 MySQL 客戶端</td></tr></tbody></table><blockquote><p><strong>MySQL 5.7 舊版語法</strong>：<code>SET PASSWORD FOR &#39;root&#39;@&#39;localhost&#39; = PASSWORD(&#39;新密碼&#39;);</code></p></blockquote><hr><h3 id="步驟-5-關閉臨時-mysqld-重新正常啟動" tabindex="-1">步驟 5：關閉臨時 mysqld，重新正常啟動 <a class="header-anchor" href="#步驟-5-關閉臨時-mysqld-重新正常啟動" aria-label="Permalink to &quot;步驟 5：關閉臨時 mysqld，重新正常啟動&quot;">​</a></h3><p>回到<strong>步驟 2 的 PowerShell 視窗</strong>，按 <code>Ctrl+C</code> 終止前景執行的 <code>mysqld.exe</code>。</p><p>然後啟動正常服務：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">net start MySQL80</span></span></code></pre></div><hr><h3 id="步驟-6-驗證新密碼" tabindex="-1">步驟 6：驗證新密碼 <a class="header-anchor" href="#步驟-6-驗證新密碼" aria-label="Permalink to &quot;步驟 6：驗證新密碼&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">&amp;</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">C:\\Program Files\\MySQL\\MySQL Server 8.0\\bin\\mysql.exe</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> -</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">u root </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">p</span></span></code></pre></div><p>輸入剛設定的新密碼，能成功登入即代表重設完成。</p><h2 id="視覺化說明" tabindex="-1">視覺化說明 <a class="header-anchor" href="#視覺化說明" aria-label="Permalink to &quot;視覺化說明&quot;">​</a></h2><h3 id="操作流程圖" tabindex="-1">操作流程圖 <a class="header-anchor" href="#操作流程圖" aria-label="Permalink to &quot;操作流程圖&quot;">​</a></h3>`,48),A=a("hr",null,null,-1),g=a("h3",{id:"服務模式切換概念圖",tabindex:"-1"},[s("服務模式切換概念圖 "),a("a",{class:"header-anchor",href:"#服務模式切換概念圖","aria-label":'Permalink to "服務模式切換概念圖"'},"​")],-1),y={class:"tip custom-block"},B=a("p",{class:"custom-block-title"},"視覺化工具",-1),C=n('<h2 id="常見問題-faq" tabindex="-1">常見問題 FAQ <a class="header-anchor" href="#常見問題-faq" aria-label="Permalink to &quot;常見問題 FAQ&quot;">​</a></h2><h3 id="q1-執行-net-stop-mysql80-顯示「服務名稱無效」怎麼辦" tabindex="-1">Q1: 執行 <code>net stop MySQL80</code> 顯示「服務名稱無效」怎麼辦？ <a class="header-anchor" href="#q1-執行-net-stop-mysql80-顯示「服務名稱無效」怎麼辦" aria-label="Permalink to &quot;Q1: 執行 `net stop MySQL80` 顯示「服務名稱無效」怎麼辦？&quot;">​</a></h3><p><strong>A:</strong> MySQL 服務名稱取決於安裝時的設定。查詢正確名稱：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 方法 1：用 sc query 找出所有 MySQL 相關服務</span></span>\n<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">sc query state</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">=</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> all </span><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">|</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> findstr </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">i mysql</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"># 方法 2：用 Get-Service 列出</span></span>\n<span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">Get-Service</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> -</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">Name </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">*</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">mysql</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">*</span></span></code></pre></div><p>常見服務名稱：<code>MySQL80</code>、<code>MySQL57</code>、<code>MySQL</code>、<code>MySQL84</code>。</p><hr><h3 id="q2-連線時出現-error-2003-hy000-can-t-connect-to-mysql-server" tabindex="-1">Q2: 連線時出現 <code>ERROR 2003 (HY000): Can&#39;t connect to MySQL server</code>？ <a class="header-anchor" href="#q2-連線時出現-error-2003-hy000-can-t-connect-to-mysql-server" aria-label="Permalink to &quot;Q2: 連線時出現 `ERROR 2003 (HY000): Can&#39;t connect to MySQL server`？&quot;">​</a></h3><p><strong>A:</strong> 常見原因與解法：</p><table><thead><tr><th>原因</th><th>解決方式</th></tr></thead><tbody><tr><td>mysqld 未啟動或已掛掉</td><td>確認步驟 2 的 PowerShell 視窗仍在執行 mysqld</td></tr><tr><td>Port 被佔用 / 衝突</td><td>檢查 <code>my.ini</code> 中的 <code>port</code> 設定，預設 3306</td></tr><tr><td><code>--shared-memory</code> 衝突</td><td>嘗試移除 <code>--shared-memory</code> 參數，改用 TCP/IP 連線</td></tr><tr><td>防火牆阻擋</td><td>臨時關閉防火牆測試，或允許 3306 port</td></tr></tbody></table><hr><h3 id="q3-執行-alter-user-出現-error-1290-hy000-the-mysql-server-is-running-with-the-skip-grant-tables-option-so-it-cannot-execute-this-statement" tabindex="-1">Q3: 執行 <code>ALTER USER</code> 出現 <code>ERROR 1290 (HY000): The MySQL server is running with the --skip-grant-tables option so it cannot execute this statement</code>？ <a class="header-anchor" href="#q3-執行-alter-user-出現-error-1290-hy000-the-mysql-server-is-running-with-the-skip-grant-tables-option-so-it-cannot-execute-this-statement" aria-label="Permalink to &quot;Q3: 執行 `ALTER USER` 出現 `ERROR 1290 (HY000): The MySQL server is running with the --skip-grant-tables option so it cannot execute this statement`？&quot;">​</a></h3><p><strong>A:</strong> <strong>漏掉第一個 <code>FLUSH PRIVILEGES;</code></strong>。在 skip-grant-tables 模式下，權限表未載入記憶體，必須先手動 <code>FLUSH PRIVILEGES</code> 才能執行 <code>ALTER USER</code>。</p><hr><h3 id="q4-密碼包含特殊字元-如-、-、-、-怎麼辦" tabindex="-1">Q4: 密碼包含特殊字元（如 <code>@</code>、<code>#</code>、<code>$</code>、<code>!</code>）怎麼辦？ <a class="header-anchor" href="#q4-密碼包含特殊字元-如-、-、-、-怎麼辦" aria-label="Permalink to &quot;Q4: 密碼包含特殊字元（如 `@`、`#`、`$`、`!`）怎麼辦？&quot;">​</a></h3><p><strong>A:</strong> 在 SQL 中用單引號包裹，並在 PowerShell 中用雙引號包裹整個指令：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">&amp;</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">C:\\Program Files\\MySQL\\MySQL Server 8.0\\bin\\mysql.exe</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> -</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">u root </span><span style="--shiki-light:#999999;--shiki-dark:#666666;">-</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">e </span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">ALTER USER &#39;root&#39;@&#39;localhost&#39; IDENTIFIED BY &#39;P@ssw0rd#123&#39;; FLUSH PRIVILEGES;</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&quot;</span></span></code></pre></div><p>或是在 MySQL 互動模式中直接輸入（推薦，避免轉義問題）。</p><hr><h3 id="q5-有多個-root-帳號-如-root-、root-127-0-0-1-要一起改嗎" tabindex="-1">Q5: 有多個 root 帳號（如 <code>root@%</code>、<code>root@127.0.0.1</code>）要一起改嗎？ <a class="header-anchor" href="#q5-有多個-root-帳號-如-root-、root-127-0-0-1-要一起改嗎" aria-label="Permalink to &quot;Q5: 有多個 root 帳號（如 `root@%`、`root@127.0.0.1`）要一起改嗎？&quot;">​</a></h3><p><strong>A:</strong> 建議<strong>全部修改</strong>，避免日後連線方式不同導致無法登入：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">FLUSH PRIVILEGES;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">ALTER</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> USER</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">root</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">@</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">localhost</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> IDENTIFIED </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">BY</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">新密碼</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">;</span></span>\n<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">ALTER</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> USER</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">root</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">@</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">127.0.0.1</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> IDENTIFIED </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">BY</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">新密碼</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">;</span></span>\n<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">ALTER</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> USER</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">root</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">@</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">%</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> IDENTIFIED </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">BY</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">新密碼</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">FLUSH PRIVILEGES;</span></span></code></pre></div><p>查詢現有 root 帳號：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">SELECT</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> User, Host </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">FROM</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;"> mysql</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">.</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;">user</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> WHERE</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> User </span><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">=</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">root</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">;</span></span></code></pre></div><hr><h3 id="q6-mysql-8-0-4-以上版本支援-caching-sha2-password-密碼修改後無法用舊客戶端連線" tabindex="-1">Q6: MySQL 8.0.4 以上版本支援 <code>caching_sha2_password</code>，密碼修改後無法用舊客戶端連線？ <a class="header-anchor" href="#q6-mysql-8-0-4-以上版本支援-caching-sha2-password-密碼修改後無法用舊客戶端連線" aria-label="Permalink to &quot;Q6: MySQL 8.0.4 以上版本支援 `caching_sha2_password`，密碼修改後無法用舊客戶端連線？&quot;">​</a></h3><p><strong>A:</strong> 若舊版客戶端（如老版 Navicat、舊版 JDBC）無法連線，可指定使用 <code>mysql_native_password</code>：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">ALTER</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> USER</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">root</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">@</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">localhost</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> IDENTIFIED </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">WITH</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> mysql_native_password </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">BY</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> &#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">新密碼</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;">;</span></span></code></pre></div><p>但建議<strong>升級客戶端</strong>而非降低安全性。</p><hr><h3 id="q7-重設完密碼後-應用程式連不上資料庫" tabindex="-1">Q7: 重設完密碼後，應用程式連不上資料庫？ <a class="header-anchor" href="#q7-重設完密碼後-應用程式連不上資料庫" aria-label="Permalink to &quot;Q7: 重設完密碼後，應用程式連不上資料庫？&quot;">​</a></h3><p><strong>A:</strong> 檢查應用程式的連線字串/設定檔，更新密碼。常見位置：</p><ul><li><code>.env</code>、<code>config.json</code>、<code>application.yml</code>、<code>web.config</code></li><li>Docker 環境變數 <code>MYSQL_ROOT_PASSWORD</code></li><li>Kubernetes Secret</li></ul><hr><h2 id="最佳實踐" tabindex="-1">最佳實踐 <a class="header-anchor" href="#最佳實踐" aria-label="Permalink to &quot;最佳實踐&quot;">​</a></h2><h3 id="✅-推薦做法" tabindex="-1">✅ 推薦做法 <a class="header-anchor" href="#✅-推薦做法" aria-label="Permalink to &quot;✅ 推薦做法&quot;">​</a></h3><ol><li><strong>使用密碼管理器</strong> - 避免再次遺忘，建議使用 Bitwarden、1Password、KeePass 等工具</li><li><strong>建立專用管理帳號</strong> - 不直接用 root 給應用程式連線，建立權限最小化的帳號</li><li><strong>定期備份與輪換</strong> - 設定提醒每 90-180 天輪換一次密碼</li><li><strong>記錄操作日誌</strong> - 重設密碼時記錄時間、操作人、原因，方便審計追蹤</li></ol><h3 id="❌-常見錯誤" tabindex="-1">❌ 常見錯誤 <a class="header-anchor" href="#❌-常見錯誤" aria-label="Permalink to &quot;❌ 常見錯誤&quot;">​</a></h3><table><thead><tr><th>錯誤</th><th>後果</th><th>如何避免</th></tr></thead><tbody><tr><td>忘記執行第一個 <code>FLUSH PRIVILEGES</code></td><td><code>ALTER USER</code> 失敗，無法修改密碼</td><td>腦中建立「skip-grant-tables 必須先 FLUSH」的肌肉記憶</td></tr><tr><td>沒加 <code>--shared-memory</code></td><td>Windows 上無法連線、報錯</td><td>照著指令完整複製貼上，不要省略參數</td></tr><tr><td>修改密碼後忘記 <code>net start MySQL80</code></td><td>服務仍在 skip-grant-tables 模式，極度不安全</td><td>設定檢查清單，驗證步驟 6 成功才算結束</td></tr><tr><td>只改 <code>root@localhost</code></td><td>遠端或 127.0.0.1 連線仍用舊密碼</td><td>統一修改所有 root 帳號，或確認應用程式連線方式</td></tr></tbody></table><hr><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><h3 id="相關文章" tabindex="-1">相關文章 <a class="header-anchor" href="#相關文章" aria-label="Permalink to &quot;相關文章&quot;">​</a></h3><p>本站相關主題：</p>',42),D=a("h3",{id:"推薦資源",tabindex:"-1"},[s("推薦資源 "),a("a",{class:"header-anchor",href:"#推薦資源","aria-label":'Permalink to "推薦資源"'},"​")],-1),u=a("p",null,"外部優質資源：",-1),m=a("h3",{id:"下一步學習",tabindex:"-1"},[s("下一步學習 "),a("a",{class:"header-anchor",href:"#下一步學習","aria-label":'Permalink to "下一步學習"'},"​")],-1),b=a("li",null,[s("想要實際應用？試試建立"),a("strong",null,"唯讀帳號"),s("、"),a("strong",null,"開發帳號"),s("、"),a("strong",null,"備份帳號"),s("並實踐最小權限原則")],-1),S